import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Cloudflare R2 Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/cloudflare-r2.md","filePath":"bn-BD/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"bn-BD/upload/cloudflare-r2.md"};function c(u,e,s,h,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-r2-channel-যোগ-করা" tabindex="-1">Cloudflare R2 Channel যোগ করা <a class="header-anchor" href="#cloudflare-r2-channel-যোগ-করা" aria-label="Permalink to &quot;Cloudflare R2 Channel যোগ করা&quot;">​</a></h1><h2 id="কখন-সবচেয়ে-উপযোগী" tabindex="-1">কখন সবচেয়ে উপযোগী <a class="header-anchor" href="#কখন-সবচেয়ে-উপযোগী" aria-label="Permalink to &quot;কখন সবচেয়ে উপযোগী&quot;">​</a></h2><p>Cloudflare R2 ব্যবহার করুন যখন:</p><ul><li>আপনার ImgBed site আগে থেকেই Cloudflare-এ deploy করা এবং একই Cloudflare account-এর R2 bucket-এ files রাখতে চান।</li><li>আলাদা S3 endpoint, access key এবং secret key configure করতে চান না।</li><li>Worker বা Pages R2 binding দিয়ে কম setup-এ read/write চালাতে চান।</li></ul><p>সংক্ষেপে:</p><p>R2 channel ImgBed admin panel-এর ভেতরে manually তৈরি করা হয় না। আগে Cloudflare project-এ একটি R2 bucket bind করতে হবে, এবং binding variable name অবশ্যই <code>img_r2</code> হতে হবে।</p><h2 id="শুরু-করার-আগে-যা-লাগবে" tabindex="-1">শুরু করার আগে যা লাগবে <a class="header-anchor" href="#শুরু-করার-আগে-যা-লাগবে" aria-label="Permalink to &quot;শুরু করার আগে যা লাগবে&quot;">​</a></h2><ul><li>একটি Cloudflare account।</li><li>আগে থেকে তৈরি একটি R2 bucket।</li><li>যে Cloudflare project-এ ImgBed deploy করা আছে সেটি manage করার permission।</li></ul><h2 id="cloudflare-এ-configure-করুন" tabindex="-1">Cloudflare-এ Configure করুন <a class="header-anchor" href="#cloudflare-এ-configure-করুন" aria-label="Permalink to &quot;Cloudflare-এ Configure করুন&quot;">​</a></h2><h3 id="_1-r2-bucket-তৈরি-করুন" tabindex="-1">1. R2 Bucket তৈরি করুন <a class="header-anchor" href="#_1-r2-bucket-তৈরি-করুন" aria-label="Permalink to &quot;1. R2 Bucket তৈরি করুন&quot;">​</a></h3><ol><li>Cloudflare Dashboard-এ log in করুন।</li><li><code>R2 Object Storage</code> খুলুন।</li><li>Create bucket ক্লিক করুন।</li><li>Bucket name দিন, যেমন <code>imgbed</code>।</li></ol><p>Uploaded files এই bucket-এ সংরক্ষিত হবে।</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bucket-কে-imgbed-project-এ-bind-করুন" tabindex="-1">2. Bucket-কে ImgBed Project-এ Bind করুন <a class="header-anchor" href="#_2-bucket-কে-imgbed-project-এ-bind-করুন" aria-label="Permalink to &quot;2. Bucket-কে ImgBed Project-এ Bind করুন&quot;">​</a></h3><p>আপনার deployment type অনুযায়ী binding location নির্বাচন করুন:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Binding যোগ করার সময় গুরুত্বপূর্ণ fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>আপনার তৈরি করা bucket নির্বাচন করুন।</td></tr></tbody></table><p>Variable name হুবহু <code>img_r2</code> হতে হবে। R2 files upload, read এবং delete—সবকিছু এই binding name-এর ওপর নির্ভর করে।</p><h3 id="_3-project-redeploy-করুন" tabindex="-1">3. Project Redeploy করুন <a class="header-anchor" href="#_3-project-redeploy-করুন" aria-label="Permalink to &quot;3. Project Redeploy করুন&quot;">​</a></h3><p>Binding save করার পর ImgBed redeploy করুন, যাতে Worker বা Pages runtime <code>img_r2</code> access করতে পারে।</p><h2 id="imgbed-এ-কী-দেখবেন" tabindex="-1">ImgBed-এ কী দেখবেন <a class="header-anchor" href="#imgbed-এ-কী-দেখবেন" aria-label="Permalink to &quot;ImgBed-এ কী দেখবেন&quot;">​</a></h2><p>R2 binding available হলে খুলুন:</p><ol><li>System Settings।</li><li>Upload Settings।</li><li><code>Cloudflare R2</code> channel।</li></ol><p>System automatically একটি fixed channel তৈরি করে:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>এটি fixed binding channel। এটি তৈরি করতে Add Channel ক্লিক করতে হবে না, এবং সাধারণ channel-এর মতো delete করা যায় না।</p><h2 id="admin-panel-এ-editable-fields" tabindex="-1">Admin Panel-এ Editable Fields <a class="header-anchor" href="#admin-panel-এ-editable-fields" aria-label="Permalink to &quot;Admin Panel-এ Editable Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>কাজ</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>R2 upload selection-এ অংশ নেবে কি না control করে।</td><td>Yes</td></tr><tr><td>Account ID</td><td>Quota limits enabled হলে official R2 usage query করতে ব্যবহার হয়।</td><td>Quota limits enabled হলে recommended</td></tr><tr><td>Bucket name</td><td>Quota limits enabled হলে official R2 usage query করতে ব্যবহার হয়।</td><td>Quota limits enabled হলে recommended</td></tr><tr><td>Quota limit</td><td>Capacity অনুযায়ী এই R2 channel upload selection-এ অংশ নেবে কি না control করে।</td><td>No</td></tr><tr><td>Threshold</td><td>Usage নির্দিষ্ট percentage-এ পৌঁছালে এই channel-এ writing বন্ধ করে।</td><td>Quota limits enabled হলে required</td></tr></tbody></table><p>Cloudflare dashboard-এর account information panel থেকে Account ID copy করতে পারেন। শুধু তখনই দিন যখন ImgBed দিয়ে R2 quota usage query এবং enforce করতে চান।</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Cloudflare-এ R2 bucket তৈরি করুন।</li><li>ImgBed project-এর Cloudflare settings খুলুন।</li><li>R2 bucket binding যোগ করুন।</li><li><code>Variable name</code> হিসেবে <code>img_r2</code> দিন।</li><li>তৈরি করা R2 bucket নির্বাচন করুন।</li><li>Binding save করে ImgBed redeploy করুন।</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings-এ ফিরে আসুন।</li><li><code>Cloudflare R2</code> channel দেখা যাচ্ছে এবং enabled আছে কি না confirm করুন।</li></ol><p>Capacity অনুযায়ী R2 upload selection-এ অংশ নিক চাইলে quota limit enable করুন, তারপর Account ID, bucket name, quota limit এবং threshold দিয়ে save করুন।</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="কীভাবে-যাচাই-করবেন" tabindex="-1">কীভাবে যাচাই করবেন <a class="header-anchor" href="#কীভাবে-যাচাই-করবেন" aria-label="Permalink to &quot;কীভাবে যাচাই করবেন&quot;">​</a></h2><ul><li>Upload Settings-এ fixed <code>Cloudflare R2</code> channel দেখা যায়।</li><li>Channel card-এ enabled দেখায়।</li><li>ছোট test file successfully upload হয় এবং returned link normalভাবে খোলে।</li><li>File খুললে <code>R2 database binding is not configured</code> দেখালে runtime <code>img_r2</code> binding পায়নি। Cloudflare-এ binding name check করে project redeploy করুন।</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
